import './FusionInZamoskvorechye.css'

import fusionHero from '../../assets/private/Квартира Замоскворечье/fusion-hero.png'
import fusionCover from '../../assets/private/Квартира Замоскворечье/ОБЛОЖКА.jpg'

import fusionGallery1 from '../../assets/private/Квартира Замоскворечье/8.jpg'
import fusionGallery2 from '../../assets/private/Квартира Замоскворечье/12 (2).jpg' 
import fusionGallery3 from '../../assets/private/Квартира Замоскворечье/9.jpg'
import fusionGallery4 from '../../assets/private/Квартира Замоскворечье/5 (2).jpg'
import fusionGallery5 from '../../assets/private/Квартира Замоскворечье/4 (2).jpg'
import fusionGallery6 from '../../assets/private/Квартира Замоскворечье/13.jpg' 

import arrow from '../../assets/icons/arrowhead-up.png'
import InfiniteImageSlider from '../../components/InfiniteImageSlider/InfiniteImageSlider'
import { useState } from 'react'
import { useTranslation } from 'react-i18next';

function FusionInZamoskvorechye() {
    const { t } = useTranslation();
    const images = [fusionCover, fusionGallery1,fusionGallery2,fusionGallery3,fusionGallery4,fusionGallery5,fusionGallery6]
    const [sliderStartIndex, setSliderStartIndex] = useState(0)
    const [sliderVisible, setSliderVisible] = useState(false)

    const handleFusionImageClick = (index) => {
        setSliderStartIndex(index)
        setSliderVisible(true)
    }
    
    const closeSlider = () => {
            setSliderVisible(false)
    }

    return ( 
        <section id='Fusion'>
            <div className="fusion-block fusion-hero">
                <div className="fusion-title-container">
                    <span className="fusion-title">{t("Fusion in Zamoskvorechye")}</span>
                    <span className="fusion-city">{t("Moscow")}</span>
                    <span className="fusion-year"> 2021 </span>
                </div>
                <img src={fusionHero} className='fusion-hero-image' alt="" />
                <div className="fusion-decription">
                    <p className="fusion-decription-text">
                       {t("fusion-decription-text")}
                    </p>
                    <img src={fusionCover} className='fusion-cover fusion-slider' alt="" onClick={()=> 
                            handleFusionImageClick(0)}/>
                </div>
            </div>
            <div className="fusion-block fusion-gallery">
                <img src={fusionGallery1} alt="" className="gallery-photo fusion-slider" onClick={()=> 
                        handleFusionImageClick(1)} loading='lazy'/>
                <img src={fusionGallery2} alt="" className="gallery-photo fusion-slider" onClick={()=> 
                        handleFusionImageClick(2)} loading='lazy'/>
                <img src={fusionGallery3} alt="" className="gallery-photo fusion-slider" onClick={()=> 
                        handleFusionImageClick(3)} loading='lazy'/>
            </div>
            <div className="fusion-block  fusion-single">
                <img src={fusionGallery4} alt="" className="gallery-photo-single fusion-slider" 
                    onClick={()=> handleFusionImageClick(4)} loading='lazy'/>
            </div>
            <div className="fusion-block fusion-double">
                <img src={fusionGallery5} alt="" className="gallery-photo-double fusion-slider" 
                    onClick={()=> handleFusionImageClick(5)} loading='lazy'/>
                <img src={fusionGallery6} alt="" className="gallery-photo-double fusion-slider" 
                    onClick={()=> handleFusionImageClick(6)} loading='lazy'/>
            </div>

            <a href="#Fusion">
                <button className="home-projects-anchor-btn" ><img src={arrow} alt="" /></button>
            </a>
            {sliderVisible ? <InfiniteImageSlider content={images} startIndex={sliderStartIndex} closeFunction={closeSlider}/> : <></> }
        </section> 
    );
}

export default FusionInZamoskvorechye;